def onCook(scriptOp):
	scriptOp.clear()

	scriptOp.copy(scriptOp.inputs[0])

	nrows = scriptOp.numRows
	for row in range(0, nrows):

		n = scriptOp[row, 2]

		if n=='1' :
			if row==(nrows-1) or nrows==1:
				scriptOp[row,3] = 1
			elif scriptOp[row,0] == scriptOp[row+1,0] :
				scriptOp[row,3] = 0
				scriptOp[row,4] = scriptOp[row+1, 1]
			else:
				scriptOp[row,3] = 1

		if n=='2' :
			if row==0 or nrows==1:
				scriptOp[row,3] = 2
			elif scriptOp[row,0] == scriptOp[row-1,0] :
				scriptOp[row,3] = 0
				scriptOp[row,4] = scriptOp[row-1, 1]
			else:
				scriptOp[row,3] = 2

	return

