def onCook(scriptOp):
	so = scriptOp
	so.copy(so.inputs[0])

	inop = scriptOp.inputs[0]

	flagop = scriptOp
	flagop.clear()
	flagop.appendRow( ['', '', 'relpath', 'item', 'detail', 'value1', 'value2'] )


	for row in range(0, inop.numRows):

		op1 = op(int(inop[row,1]))
		op2 = op(int(inop[row,4]))

		relpath = inop[row,0].val
		if relpath == '' :
			relpath = '..'

		#print(op1.path) 

		if parent().par.Flags :
			if op1.lock != op2.lock :
				flagop.appendRow( ['', '', relpath, 'flag', 'lock', op1.lock, op2.lock] )

			if op1.bypass != op2.bypass :
				flagop.appendRow( ['', '', relpath, 'flag', 'bypass', op1.bypass, op2.bypass] )

			if op1.allowCooking != op2.allowCooking :
				flagop.appendRow( ['', '', relpath, 'flag', 'allowCooking', op1.allowCooking, op2.allowCooking] )

			if op1.cloneImmune != op2.cloneImmune :
				flagop.appendRow( ['', '', relpath, 'flag', 'cloneImmune', op1.cloneImmune, op2.cloneImmune] )

			if op1.render != op2.render :
				flagop.appendRow( ['', '', relpath, 'flag', 'render', op1.render, op2.render] )

			if op1.display != op2.display :
				flagop.appendRow( ['', '', relpath, 'flag', 'display', op1.display, op2.display] )

			if op1.python != op2.python :
				flagop.appendRow( ['', '', relpath, 'flag', 'python', op1.python, op2.python] )

			if (op1.isCHOP or op1.isDAT) and (op2.isCHOP or op2.isDAT) :
				if op1.export != op2.export :
					flagop.appendRow( ['', '', relpath, 'flag', 'export', op1.export, op2.export] )


		if parent().par.Familytype :
			if op1.OPType != op2.OPType :
				flagop.appendRow( ['', '', relpath, 'type', '', op1.OPType, op2.OPType] )


		if parent().par.Parameters :

			if op1.OPType == op2.OPType :

				pars1 = op1.pars()
				pars2 = op2.pars()

				if len(pars1) != len(pars2) :
					flagop.appendRow( ['', '', relpath, 'par qty', '', len(pars1), len(pars2)] )

				try:
					for p1, p2 in zip(pars1, pars2) :
						if p1.name == p2.name :
							if p1.val != p2.val :
								flagop.appendRow( ['', '', relpath, 'par val', p1.name, p1.val, p2.val] )
							if p1.expr != p2.expr :
								flagop.appendRow( ['', '', relpath, 'par expr', p1.name, "'" + str(p1.expr) + "'", "'" + str(p2.expr) + "'"] )
							if p1.mode != p2.mode :
								flagop.appendRow( ['', '', relpath, 'par mode', p1.name, p1.mode, p2.mode] )
						else :
								flagop.appendRow( ['', '', relpath, 'par name', '', p1.name, p2.name] )
				except:
					flagop.appendRow( ['', '', relpath, 'par mismatch'] )
					pass

		if parent().par.Wiring :
			lconn1 = []
			lconn2 = []

			for incons in op1.inputConnectors :
				conn = incons.connections
				lconn1 += [ conn[0].owner.name if conn else None ]

			for incons in op2.inputConnectors :
				conn = incons.connections
				lconn2 += [ conn[0].owner.name if conn else None ]

			if lconn1 != lconn2 :
				flagop.appendRow( ['', '', relpath, 'input wires', '', lconn1, lconn2] )


			if op1.isCOMP and op2.isCOMP :

				for incons in op1.inputCOMPConnectors :
					conn = incons.connections
					lconn1 += [ conn[0].owner.name if conn else None ]

				for incons in op2.inputCOMPConnectors :
					conn = incons.connections
					lconn2 += [ conn[0].owner.name if conn else None ]

				if lconn1 != lconn2 :
					flagop.appendRow( ['', '', relpath, 'hierarchy', '', lconn1, lconn2] )


		if parent().par.Datcontents :
			if op1.isDAT and op2.isDAT :
				types = [ 'text', 'table', 'chopexec', 'datexec', 'execute', 'opexec', 'panelexec', 'parexec' ]

				if (op1.type in types) or (op1.lock and op2.lock):
					if op1.text != op2.text :
						splitlines1 = op1.text.splitlines()
						splitlines2 = op2.text.splitlines()
						len1 = len(splitlines1)
						len2 = len(splitlines2)

						found = 0
						for	i in range(0, min(len1, len2)) :
							if splitlines1[i] != splitlines2[i] :
								line1 =  splitlines1[i].replace('\t', ' ') 
								line2 =  splitlines2[i].replace('\t', ' ') 
								flagop.appendRow( ['', '', relpath, 'dat', 'contents', str(i) + ': ' + line1, str(i) + ': ' + line2] )
								found = 1
								break
						if not found and (len1 != len2) :
							flagop.appendRow( ['', '', relpath, 'dat', 'contents', 'length ' + str(len1), 'length ' + str(len2)] )


		#if parent().par.Lockchops :
		#	if op1.isCHOP and op2.isCHOP :
		#		if op1.lock and op2.lock :				
		#			if (len(op1) != len(op2)) or (op1.numSamples != op2.numSamples)
		#				flagop.appendRow( ['', '', relpath, 'chop', 'contents'] )
		#			now compare contents

		if parent().par.Misc :
			if op1.tags != op2.tags :
				flagop.appendRow( ['', '', relpath, 'tags', '', op1.tags, op2.tags] )

			if op1.comment != op2.comment :
				comment1 = op1.comment if len(op1.comment)<17 else op1.comment[:15] + ' ...'
				comment2 = op2.comment if len(op2.comment)<17 else op2.comment[:15] + ' ...'
				flagop.appendRow( ['', '', relpath, 'comment', '', comment1, comment2] )


		if parent().par.Cosmetics :

			if op1.nodeX != op2.nodeX or op1.nodeY != op2.nodeY :
				flagop.appendRow( ['', '', relpath, 'cosmetic', 'node X Y'] )

			if op1.activeViewer != op2.activeViewer :
				flagop.appendRow( ['', '', relpath, 'cosmetic', 'activeViewer', op1.activeViewer, op2.activeViewer] )

			if op1.viewer != op2.viewer :
				flagop.appendRow( ['', '', relpath, 'cosmetic', 'viewer', op1.viewer, op2.viewer] )


	return

